Here is a simple C# snippet that shows how I clamp a custom impulse before applying it to Juan's Rigidbody:

```csharp
using UnityEngine;

public class JuanJumpHelper : MonoBehaviour
{
    [SerializeField] private Rigidbody targetBody;
    [SerializeField] private float maxImpulse = 12f;

    public void AddJumpImpulse(Vector3 impulse)
    {
        if (targetBody == null) return;

        // Keep force stable across levels and frame rates.
        Vector3 safeImpulse = Vector3.ClampMagnitude(impulse, maxImpulse);
        targetBody.AddForce(safeImpulse, ForceMode.Impulse);
    }
}
```
